/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWPlanoContas-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PlanHie.IsEmpty() AND &PlanCatTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Hierarquia") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanHie) WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Tipo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = '' do Case Case &PlanCatTip.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "CRÉDITO"
Case &PlanCatTip.ToString().Trim() = "D" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "DÉBITO"
EndCase EndIf If not (&PlanAnaSin.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Sintético") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &PlanAnaSin.ToString().Trim() = "A" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "ANALÍTICO"
Case &PlanAnaSin.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "SINTÉTICO"
EndCase EndIf
If not (&PlanUtiTra.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Transferências?") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &PlanUtiTra.ToString() EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PLANNOMCMP' &PlanNomCmp1.FromString(&GridStateDynamicFilter.Value) If not &PlanNomCmp1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cmp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanNomCmp1) EndIf Case &DynamicFiltersSelector1 = !'PLANNOM' &PlanNom1.FromString(&GridStateDynamicFilter.Value) If not &PlanNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanNom1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PLANNOMCMP' &PlanNomCmp2.FromString(&GridStateDynamicFilter.Value) If not &PlanNomCmp2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cmp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanNomCmp2) EndIf Case &DynamicFiltersSelector2 = !'PLANNOM' &PlanNom2.FromString(&GridStateDynamicFilter.Value) If not &PlanNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanNom2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PLANNOMCMP' &PlanNomCmp3.FromString(&GridStateDynamicFilter.Value) If not &PlanNomCmp3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cmp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanNomCmp3) EndIf Case &DynamicFiltersSelector3 = !'PLANNOM' &PlanNom3.FromString(&GridStateDynamicFilter.Value) If not &PlanNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PlanNom3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Hierarquia" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Nome Cmp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Sintético" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Grupo Dre"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PlanHiePadL when &OrderedBy = 1 order PlanHie when &OrderedBy = 2 AND &OrderedDsc = False order (PlanHie) when &OrderedBy = 2 AND &OrderedDsc = True order PlanNom when &OrderedBy = 3 AND &OrderedDsc = False order (PlanNom) when &OrderedBy = 3 AND &OrderedDsc = True order PlanNomCmp when &OrderedBy = 4 AND &OrderedDsc = False order (PlanNomCmp) when &OrderedBy = 4 AND &OrderedDsc = True order PlanAnaSin when &OrderedBy = 5 AND &OrderedDsc = False order (PlanAnaSin) when &OrderedBy = 5 AND &OrderedDsc = True order PlanCatTip when &OrderedBy = 6 AND &OrderedDsc = False order (PlanCatTip) when &OrderedBy = 6 AND &OrderedDsc = True order PlanGrpDre when &OrderedBy = 7 AND &OrderedDsc = False order (PlanGrpDre) when &OrderedBy = 7 AND &OrderedDsc = True
using DSWWPlanoContas(&PlanHie, &PlanCatTip, &DynamicFiltersSelector1, &PlanNomCmp1, &PlanNom1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &PlanNomCmp2, &PlanNom2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PlanNomCmp3 , &PlanNom3, &PlanAnaSin, &PlanUtiTra)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(PlanHie) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(PlanNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(PlanNomCmp) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = '' do Case Case PlanAnaSin.ToString().Trim() = "A" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "ANALÍTICO"
Case PlanAnaSin.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "SINTÉTICO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = '' do Case Case PlanCatTip.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "CRÉDITO"
Case PlanCatTip.ToString().Trim() = "D" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "DÉBITO"
EndCase If Not PlanGrpDre.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = PlanGrpDre.EnumerationDescription() Endif
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWPlanoContasGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWPlanoContasGridState")) Else &GridState.FromXml(&Session.Get(!"WWPlanoContasGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PLANHIE" &PlanHie.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PLANCATTIP" &PlanCatTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PLANANASIN" &PlanAnaSin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PLANUTITRA" &PlanUtiTra.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
